@Service
class StorageService {

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("jpg", "jpeg", "png", "gif", "webp");
    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp"
    );

    private final Path uploadDir = Paths.get("public", "uploads");

    public void init() throws IOException {
        Files.createDirectories(uploadDir);
    }

    public Path getUploadDir() {
        return uploadDir;
    }

    public String store(MultipartFile file, HttpServletRequest request) throws IOException {
        if (file == null || file.isEmpty()) {
            throw new InvalidFileException("File is required");
        }

        String originalFilename = StringUtils.cleanPath(file.getOriginalFilename() == null ? "" : file.getOriginalFilename());
        String extension = getExtension(originalFilename);

        if (!ALLOWED_EXTENSIONS.contains(extension.toLowerCase())) {
            throw new InvalidFileException("Only image files are allowed: jpg, jpeg, png, gif, webp");
        }

        String contentType = file.getContentType();
        if (contentType == null || !ALLOWED_CONTENT_TYPES.contains(contentType.toLowerCase())) {
            throw new InvalidFileException("Invalid image content type");
        }

        String newFilename = Instant.now().toEpochMilli() + "-" + UUID.randomUUID() + "." + extension.toLowerCase();
        Path target = uploadDir.resolve(newFilename).normalize();

        if (!target.startsWith(uploadDir.normalize())) {
            throw new InvalidFileException("Invalid file path");
        }

        Files.copy(file.getInputStream(), target, StandardCopyOption.REPLACE_EXISTING);

        return buildFileUrl(request, newFilename);
    }

    public Resource loadAsResource(String filename) throws MalformedURLException {
        Path file = uploadDir.resolve(filename).normalize();
        return new UrlResource(file.toUri());
    }

    private String buildFileUrl(HttpServletRequest request, String filename) {
        String scheme = request.getScheme();
        String serverName = request.getServerName();
        int serverPort = request.getServerPort();
        String contextPath = request.getContextPath();

        boolean defaultPort = ("http".equalsIgnoreCase(scheme) && serverPort == 80)
                || ("https".equalsIgnoreCase(scheme) && serverPort == 443);

        String portPart = defaultPort ? "" : ":" + serverPort;
        return scheme + "://" + serverName + portPart + contextPath + "/uploads/" + filename;
    }

    private String getExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        if (lastDot == -1 || lastDot == filename.length() - 1) {
            return "";
        }
        return filename.substring(lastDot + 1);
    }
}

